args.sparql:
SELECT ?club ?manager WHERE {
  ?league rdfs:label "National Premier League"@en;
          wdt:P17 wd:Q147.
  ?club wdt:P361 ?league;
        wdt:P580 ?clubStart;
        wdt:P585 ?clubEnd.
  FILTER (YEAR(?clubStart) = 2016)
  FILTER (YEAR(?clubEnd) = 2017)
  ?club wdt:P65 ?stadium.
  ?stadium wdt:P652 ?capacity.
  FILTER (?capacity = 3000)
  ?club wdt:P1732 ?manager.
  ?manager wdt:P580 ?managerStart.
  ?manager wdt:P585 ?managerEnd.
  FILTER (MIN(?clubStart, ?managerStart) <= MAX(?clubEnd, ?managerEnd))
}

SELECT ?club ?manager WHERE {
  ?league rdfs:label "National Premier League"@en;
          wdt:P17 wd:Q147.
  ?club wdt:P361 ?league;
        wdt:P580 ?clubStart;
        wdt:P585 ?clubEnd.
  FILTER (YEAR(?clubStart) = 2016)
  FILTER (YEAR(?clubEnd) = 2017)
  ?club wdt:P479 ?stadium.
  ?stadium wdt:P652 ?capacity.
  FILTER (?capacity = 3000)
  ?club wdt:P1732 ?manager.
  ?manager wdt:P580 ?managerStart.
  ?manager wdt:P585 ?managerEnd.
  FILTER (?clubStart <= ?managerEnd && ?clubEnd >= ?managerStart)
}
